tion.update -= OnEditorUpdate;            AssemblyReloadEvents.beforeAssemblyReload -= DisposeHost;            EditorApplication.quitting -= DisposeHost;            _syncSchedule?.Pause();            _syncSchedule = null;            DisposeHost();        }        private void StartChromeWatchdog()        {            if (s_chromeWatchThread != null && s_chromeWatchThread.IsAlive) return;            s_chromeWatchStop = false;            s_chromeWatchThread = new System.Threading.Thread(() =>            {                while (!s_chromeWatchStop)                {                    try                    {                        var hwnd = s_browserHwndForWatch;                        if (hwnd != IntPtr.Zero && EditorBrowser.Native.Win32.IsWindow(hwnd))                        {                            if (EditorBrowser.Native.Win32.GetWindowRect(hwnd, out var rc))                            {                                bool vis = EditorBrowser.Native.Win32.IsWindowVisible(hwnd);                                // === 媛뺤젣 ?꾩튂 ?좎? (drag modal loop ?고쉶 ?듭떖) ===                                // 硫붿씤 thread 李⑤떒 以?Unity dock system / OS 媛 Chrome HWND ??꺼??                                // 利됱떆 留덉?留?valid ?꾩튂濡?蹂듦?. SetWindowPos ??thread-safe.                                if (ExternalBrowserHost.s_enforceEnabled && vis)                                {                                    int ex = ExternalBrowserHost.s_enforceX;                                    int ey = ExternalBrowserHost.s_enforceY;                                    int ew = ExternalBrowserHost.s_enforceW;                                    int eh = ExternalBrowserHost.s_enforceH;                                    bool drifted = rc.Left != ex || rc.Top != ey                                                || (rc.Right - rc.Left) != ew || (rc.Bottom - rc.Top) != eh;                                    if (drifted)                                    {                                        EditorBrowser.Native.Win32.SetWindowPos(                                            hwnd, EditorBrowser.Native.Win32.HWND_TOP,                                            ex, ey, ew, eh,                                            EditorBrowser.Native.Win32.SWP_NOACTIVATE);                                    }                                }                                lock (s_chromeRingLock)                                {                                    if (!s_chromeRingFrozen)                                    {                                        s_chromeRing.Add($"{DateTime.UtcNow.Ticks} chrome=({rc.Left},{rc.Top})-({rc.Right},{rc.Bottom}) {rc.Right-rc.Left}x{rc.Bottom-rc.Top} vis={vis} enforce={(ExternalBrowserHost.s_enforceEnabled ? $"({ExternalBrowserHost.s_enforceX},{ExternalBrowserHost.s_enforceY}) {ExternalBrowserHost.s_enforceW}x{ExternalBrowserHost.s_enforceH}" : "OFF")}");                                        if (s_chromeRing.Count > 3000) s_chromeRing.RemoveAt(0);                                        bool changed = rc.Left != s_chromeLastL || rc.Top != s_chromeLastT                                                    || rc.Right != s_chromeLastR || rc.Bottom != s_chromeLastB;                                        if (changed)                                        {                                            s_chromeLastL = rc.Left; s_chromeLastT = rc.Top;                                            s_chromeLastR = rc.Right; s_chromeLastB = rc.Bottom;                                            s_chromeFreezeAtTicks = DateTime.UtcNow.Ticks + TimeSpan.FromSeconds(3).Ticks;                                        }                                        if (s_chromeFreezeAtTicks > 0 && DateTime.UtcNow.Ticks >= s_chromeFreezeAtTicks)                                            s_chromeRingFrozen = true;                                    }                                }                            }                        }                    }         